+// deno-lint-ignore-file no-explicit-any
+import { join, resolve } from "@std/path";
+import { ConfigParseError } from "./errors.ts";
+import type { ConfigOptions } from "./types.ts";
+
+export interface LoadedConfig {
+  path?: string;
+  values: Record<string, unknown>;
+}
+
+export async function loadConfig(options: ConfigOptions): Promise<LoadedConfig> {
+  const paths = options.searchPaths ?? [cwd()];
+  const formats = options.formats ?? [".json", ".rc"];
+  const matches: Array<{ path: string; format: string; content: string }> = [];
+
+  for (const searchPath of paths) {
+    for (const format of formats) {
+      const path = resolve(join(searchPath, filename(options.name, format)));
+      const content = await readFile(path);
+      if (content !== undefined) {
+        matches.push({ path, format, content });
+        if (!options.mergeConfigs) break;
+      }
+    }
+    if (matches.length && !options.mergeConfigs) break;
+  }
+
+  const values: Record<string, unknown> = {};
+  // Apply lower-precedence files first, so earlier search paths win.
+  for (const match of matches.reverse()) {
+    Object.assign(values, parse(match, options.parser));
+  }
+  return { path: matches[0]?.path, values };
+}
+
+function filename(name: string, format: string): string {
+  return format === ".rc" ? `.${name}rc` : `${name}${format}`;
+}
+
+function parse(
+  { path, format, content }: { path: string; format: string; content: string },
+  parser?: ConfigOptions["parser"],
+): Record<string, unknown> {
+  try {
+    const value = parser
+      ? parser(content)
+      : format === ".rc"
+      ? parseRc(content)
+      : JSON.parse(content);
+    if (!isPlainObject(value)) {
+      throw new Error("expected an object");
+    }
+    return flatten(value);
+  } catch (error) {
+    throw new ConfigParseError(
+      path,
+      error instanceof Error ? error.message : String(error),
+    );
+  }
+}
+
+function parseRc(content: string): Record<string, unknown> {
+  const values: Record<string, unknown> = {};
+  for (const rawLine of content.split(/\\r?\
/)) {
+    const line = rawLine.trim();
+    if (!line || line.startsWith("#")) continue;
+    const equal = line.indexOf("=");
+    if (equal === -1) throw new Error(`invalid RC entry "${rawLine}"`);
+    const key = line.slice(0, equal).trim();
+    let value = line.slice(equal + 1).trim();
+    if (!key) throw new Error(`invalid RC entry "${rawLine}"`);
+    if (value.startsWith('"')) {
+      if (!value.endsWith('"') || value.length < 2) {
+        throw new Error(`unterminated quoted value for "${key}"`);
+      }
+      value = value.slice(1, -1);
+    }
+    values[key] = coerceRcValue(value);
+  }
+  return values;
+}
+
+function coerceRcValue(value: string): string | number | boolean {
+  if (value === "true") return true;
+  if (value === "false") return false;
+  if (value !== "" && /^[-+]?(?:\\d+\\.?\\d*|\\.\\d+)(?:e[-+]?\\d+)?$/i.test(value)) {
+    return Number(value);
+  }
+  return value;
+}
+
+function flatten(value: Record<string, unknown>, prefix = ""): Record<string, unknown> {
+  return Object.entries(value).reduce<Record<string, unknown>>((result, [key, item]) => {
+    const name = prefix ? `${prefix}.${key}` : key;
+    if (isPlainObject(item)) Object.assign(result, flatten(item, name));
+    else result[name] = item;
+    return result;
+  }, {});
+}
+
+function isPlainObject(value: unknown): value is Record<string, unknown> {
+  return !!value && typeof value === "object" && !Array.isArray(value) &&
+    Object.getPrototypeOf(value) === Object.prototype;
+}
+
+function cwd(): string {
+  const { Deno, process } = globalThis as any;
+  if (Deno) return Deno.cwd();
+  if (process) return process.cwd();
+  throw new Error("unsupported runtime");
+}
+
+async function readFile(path: string): Promise<string | undefined> {
+  const { Deno, process } = globalThis as any;
+  try {
+    if (Deno) return await Deno.readTextFile(path);
+    if (process) return await (await import("node:fs/promises")).readFile(path, "utf8");
+  } catch (error) {
+    if (error instanceof Error && (error as any).code === "ENOENT") return undefined;
+    throw error;
+  }
+  throw new Error("unsupported runtime");
+}
