+import { test } from "@cliffy/internal/testing/test";
+import { assertEquals, assertRejects } from "@std/assert";
+import { Command } from "../../command.ts";
+import { ConfigParseError, ConfigValidationError } from "../../config/mod.ts";
+
+async function configDir(files: Record<string, string>): Promise<string> {
+  const dir = await Deno.makeTempDir();
+  await Promise.all(Object.entries(files).map(([name, content]) =>
+    Deno.writeTextFile(`${dir}/${name}`, content)
+  ));
+  return dir;
+}
+
+test("command: reads JSON config with CLI and environment precedence", async () => {
+  const dir = await configDir({
+    "app.json": JSON.stringify({ "port": 0, "enabled": false, "user-name": "config", nested: { value: 1 } }),
+  });
+  const command = new Command()
+    .throwErrors()
+    .config({ name: "app", searchPaths: [dir] })
+    .option("--port <port:number>", "...")
+    .option("--enabled", "...")
+    .option("--user-name <name>", "...")
+    .env("APP_PORT=<port:number>", "...", { prefix: "APP_" });
+
+  const result = await command.parse(["--user-name", "cli"]);
+  assertEquals(result.options, { port: 0, enabled: false, userName: "cli" });
+  assertEquals(command.getConfigValues(), {
+    port: 0,
+    enabled: false,
+    userName: "config",
+    "nested.value": 1,
+  });
+  assertEquals(command.getConfigPath(), `${dir}/app.json`);
+});
+
+test("command: parses RC config and merges search paths", async () => {
+  const first = await configDir({ ".apprc": 'name="Jane Doe"\
count=2\
enabled=true\
' });
+  const second = await configDir({ ".apprc": "name=second\
count=4\
" });
+  const command = new Command().throwErrors().config({
+    name: "app",
+    formats: [".rc"],
+    searchPaths: [first, second],
+    mergeConfigs: true,
+  })
+    .option("--name <name>", "...")
+    .option("--count <count:number>", "...")
+    .option("--enabled", "...");
+  const result = await command.parse([]);
+  assertEquals(result.options, { name: "Jane Doe", count: 2, enabled: true });
+});
+
+test("command: reports malformed and invalid config values", async () => {
+  const malformed = await configDir({ "app.json": "{" });
+  const invalid = await configDir({ "app.json": '{"count":"two"}' });
+  await assertRejects(
+    () => new Command().throwErrors().config({ name: "app", searchPaths: [malformed] }).parse([]),
+    ConfigParseError,
+  );
+  await assertRejects(
+    () => new Command().throwErrors().config({ name: "app", searchPaths: [invalid] })
+      .option("--count <count:number>", "...").parse([]),
+    ConfigValidationError,
+  );
+});
+
+test("command: child config overrides inherited config", async () => {
+  const parent = await configDir({ "parent.json": '{"name":"parent","shared":"parent"}' });
+  const child = await configDir({ "child.json": '{"shared":"child"}' });
+  const command = new Command().throwErrors().config({ name: "parent", searchPaths: [parent] })
+    .command("child")
+    .config({ name: "child", searchPaths: [child] })
+    .option("--name <name>", "...")
+    .option("--shared <shared>", "...");
+  const result = await command.parse(["child"]);
+  assertEquals(result.options, { name: "parent", shared: "child" });
+  assertEquals(result.cmd.getConfigValues(), { name: "parent", shared: "child" });
+});
